VALUES
  ('optician-moex-00339', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '軟式隱形眼鏡片使用加熱方式保養，下列敘述何者錯誤？', '["眼睛容易造成巨大乳突結膜炎", "會使鏡片蛋白質變性", "配戴鏡片後的視覺敏銳度會下降", "對棘阿米巴原蟲防治無效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00340', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '倫敦Moorfields眼科醫院分析（2000～2007年）連續配戴鞏膜鏡片的患者最多的主要適應症的前三名，下', '["眼表疾病", "角膜移植", "無水晶體", "圓錐角膜  ⑤屈光矯正"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00341', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '根據Chan（2014）報告顯示，配戴有色隱形眼鏡比透明隱形眼鏡更容易有何種菌體的黏附，下列何者正確？', '["棘阿米巴原蟲", "綠膿桿菌", "真菌", "大腸桿菌"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00342', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '晚間睡覺（overnight）配戴矽水膠軟式隱形眼鏡者，早上起床後，其角膜厚度有何變化？', '["因為壓迫角膜作用，角膜厚度稍微變薄", "無水腫", "大約呈現4%程度的水腫", "大約呈現5%～13%程度的水腫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00343', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜內皮層水腫（endotheliumedema）的敘述，下列何者正確？', '["戴隱形眼鏡若角膜輕微內皮層水腫（endotheliumedema），可以不需處理", "一般情况，病人通常會抱怨有視力問題", "長期的角膜缺氧使乳酸增加，而角膜的PH值升高導致角膜內皮細胞間水腫", "裂隙燈檢查，可觀察到內皮細胞間有大於3%的區域有黑點時，應立即更换高透氧的隱形眼鏡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00344', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一位 35 歲配戴硬式隱形眼鏡的女性，最近一個月來發現右眼眼瞼有輕微下垂的現象，裂隙燈檢查後你發 現病人有乳突狀結膜炎，下列敘述何者最符合這位病人的情況？', '["約有10%配戴軟式隱形眼鏡的病人會發生眼瞼下垂", "建議病人先停戴隱形眼鏡一個月，並接受結膜炎治療", "建議病人緊急接受眼瞼下垂矯正手術", "不論何種原因造成，隱形眼鏡相關的眼瞼下垂預後都很差"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00345', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關拋棄式隱形眼鏡，下列何者錯誤？', '["拋棄式隱形眼鏡在配戴後，鏡片上培養出含有包括金黃葡萄球菌的細菌機率極高", "配戴前沒有做手部清潔可能導致鏡片受污染", "未遵循清潔方式重複使用鏡片，會加劇細菌積聚", "如果開封後未即時配戴，應使用消毒藥水，再將鏡片放回原來的容器中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00346', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡引起的急性紅眼（contactlensacuteredeye），下列敘述何者錯誤？', '["通常雙眼同時發生", "伴有溢淚和畏光", "有革蘭氏陰性細菌存在", "通常在清晨被疼痛喚醒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00347', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '硬式隱形眼鏡使用時，會因為使用者順應醫囑性（compliance）不佳而造成眼睛的併發症。下列那一項是 順應性不好的行為？', '["在配戴隱形眼鏡時會先洗手", "不使用過期清潔藥水去清洗隱形眼鏡鏡片", "使用自來水作為濕潤鏡片的溶液", "定期清洗及更換隱形眼鏡盒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00348', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於在無晶體（aphakia）的病患使用隱形眼鏡的敘述，下列何者錯誤？', '["因為所需的隱形眼鏡通常較厚，較容易造成角膜缺氧", "若在年紀比較大的病患使用，因為淚水量少、瞼板腺功能不佳、眼瞼易發炎、免疫系統較差，比較容易感染", "若發生在老人，需要考慮病患是否可以自己清潔、裝卸隱形眼鏡", "小朋友不會需要開白內障，所以不會有無晶體的問題，也因此不需要使用隱形眼鏡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
